"""
Parameterized generator for GH716_remix_11170.

Source PR:    https://github.com/remix-run/remix/pull/11170
Source Issue: N/A

Seed varies: renames 'actions' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH716_remix_11170'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH716_remix_11170'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('actions', 'actions' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH716_remix_11170',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'remix-run/remix',
                "pr_number": 11170,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/remix-run/remix/pull/11170",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/workflows/publish.yaml': 'name: Publish\n\non:\n  push:\n    branches:\n      - main\n\nconcurrency: ${{ github.workflow }}-${{ github.ref }}\n\njobs:\n  check:\n    name: Check release readiness\n    runs-on: ubuntu-latest\n    outputs:\n      has_change_files: ${{ steps.check.outputs.has_change_files }}\n    steps:\n      - name: Checkout\n        uses: actions/checkout@v4\n\n      - name: Check for change files\n        id: check\n        run: |\n          # Look for change files in any package\'s .changes directory (excluding README.md)\n          change_files=$(find packages/*/.changes -name "*.md" ! -name "README.md" 2>/dev/null)\n          if [ -n "$change_files" ]; then\n            echo "Change files found (blocking publish):"\n            echo "$change_files"\n            echo "has_change_files=true" >> $GITHUB_OUTPUT\n          else\n            echo "No change files found, proceeding to publish."\n            echo "has_change_files=false" >> $GITHUB_OUTPUT\n          fi\n\n  publish:\n    name: Publish any unreleased packages\n    needs: check\n    if: needs.check.outputs.has_change_files == \'false\'\n    runs-on: ubuntu-latest\n\n    permissions:\n      contents: write # Required for creating tags and GitHub releases\n      id-token: write # OIDC ID token is used for authentication with npm/jsr\n\n    steps:\n      - name: Checkout\n        uses: actions/checkout@v4\n\n      - name: Install pnpm\n        uses: pnpm/action-setup@v4\n\n      - name: Install Node.js\n        uses: actions/setup-node@v4\n        with:\n          node-version-file: \'package.json\'\n          cache: pnpm\n\n      - name: Install dependencies\n        run: pnpm install --frozen-lockfile\n\n      - name: Get Playwright Version\n        id: playwright-version\n        run: echo "version=$(pnpm --filter @remix-run/component exec playwright --version | cut -d \' \' -f2)" >> $GITHUB_OUTPUT\n\n      - name: Cache Playwright Browsers\n        uses: actions/cache@v4\n        id: cache-browsers\n        with:\n          path: ~/.cache/ms-playwright\n          key: playwright-${{ runner.os }}-${{ steps.playwright-version.outputs.version }}\n\n      - name: Install Playwright Browsers\n        if: steps.cache-browsers.outputs.cache-hit != \'true\'\n        run: pnpm --filter @remix-run/component exec playwright install --with-deps\n\n      - name: Run tests\n        run: pnpm test\n\n      - name: Build packages\n        run: pnpm build\n\n      - name: Publish to npm and create releases\n        run: node ./scripts/publish.ts\n        env:\n          GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}\n\n  #     - name: Output tag\n  #       run: echo "tag=remix@$(node -p "require(\'./packages/remix/package.json\').version")" >> $GITHUB_OUTPUT\n\n  # docs:\n  #   name: Update API Docs\n  #   needs: publish\n  #   runs-on: ubuntu-latest\n  #   steps:\n  #     - name: Trigger remix-api-docs\n  #       uses: actions/github-script@v8\n  #       with:\n  #         github-token: ${{ secrets.REMIX_API_DOCS_PAT }}\n  #         script: |\n  #           await github.rest.repos.createDispatchEvent({\n  #             owner: \'remix-run\',\n  #             repo: \'remix-api-docs\',\n  #             event_type: \'update-docs\',\n  #             client_payload: { tag: \'${{ needs.publish.outputs.tag }}\' }\n  #           });\n',
            'docs/src/server/index.ts': "import * as http from 'node:http'\nimport { createRequestListener } from 'remix/node-fetch-server'\nimport { createRouter } from './router.tsx'\n\nlet router = createRouter()\n\nlet server = http.createServer(\n  createRequestListener(async (request) => {\n    try {\n      return await router.fetch(request)\n    } catch (error) {\n      console.error(error)\n      return new Response('Internal Server Error', { status: 500 })\n    }\n  }),\n)\n\nlet port = process.env.PORT ? parseInt(process.env.PORT, 10) : 3000\n\nserver.listen(port, () => {\n  console.log(`Remix API docs server running on http://localhost:${port}`)\n})\n\nlet shuttingDown = false\n\nfunction shutdown() {\n  if (shuttingDown) return\n  shuttingDown = true\n  server.close(() => {\n    process.exit(0)\n  })\n}\n\nprocess.on('SIGINT', shutdown)\nprocess.on('SIGTERM', shutdown)\n",
            'docs/src/server/prerender.ts': 'import * as cp from \'node:child_process\'\nimport { existsSync } from \'node:fs\'\nimport * as fs from \'node:fs/promises\'\nimport * as path from \'node:path\'\nimport * as util from \'node:util\'\nimport { parse } from \'node-html-parser\'\nimport * as semver from \'semver\'\nimport { type Router } from \'remix/fetch-router\'\nimport { createRouter, getDefaultVersions } from \'./router.tsx\'\nimport type { ServerContext } from \'./components.tsx\'\nimport { routes } from \'./routes.ts\'\n\nlet { values: cliArgs } = util.parseArgs({\n  options: {\n    dir: {\n      type: \'string\',\n      short: \'d\',\n      default: \'build/site\',\n    },\n    all: {\n      type: \'boolean\',\n      short: \'a\',\n    },\n  },\n})\n\nconst assetsDir = path.join(process.cwd(), \'build\', \'assets\')\nconst outputDir = path.join(process.cwd(), cliArgs.dir)\nconst versions = await getVersionsToBuild(outputDir, cliArgs.all === true)\nif (versions) {\n  console.log(\'Prerendering versions:\\n\', JSON.stringify(versions, null, 2))\n} else {\n  console.log(\'No remix version tags found, defaulting to current version only\')\n}\n\nconst docsRouter = createRouter(versions)\n\n// Copy static assets to the output directory\nawait fs.cp(assetsDir, path.join(outputDir, \'assets\'), { recursive: true })\nfor (let version of versions || getDefaultVersions()) {\n  if (version.crawl) {\n    await fs.cp(assetsDir, path.join(outputDir, version.version, \'assets\'), { recursive: true })\n  }\n}\n\nawait spider(\n  docsRouter,\n  outputDir,\n  new Set([\'/\', ...(versions?.filter((v) => v.crawl).map((v) => `/${v.version}/`) || [])]),\n)\n\n// Spider the website served by router, beginning at /\nasync function spider(router: Router, outputDir: string, urlQueue = new Set([\'/\'])) {\n  await fs.mkdir(outputDir, { recursive: true })\n\n  // Track URLs we have already downloaded to avoid loops\n  let downloadedUrls = new Set<string>()\n\n  for (let urlPath of urlQueue) {\n    if (urlPath && !downloadedUrls.has(urlPath)) {\n      let { downloadedUrl, discoveredUrls } = await crawl(router, urlPath, outputDir)\n      downloadedUrls.add(downloadedUrl)\n      discoveredUrls\n        .filter((href) => !downloadedUrls.has(href))\n        .forEach((href) => urlQueue.add(href))\n    }\n  }\n\n  console.log(`\\nCrawling complete!`)\n}\n\nasync function crawl(router: Router, urlPath: string, outputDir: string) {\n  let response\n  try {\n    response = await router.fetch(new Request(`http://localhost${urlPath}`))\n    if (!response.ok) {\n      throw new Error(`Error fetching ${urlPath}: ${response.status} ${response.statusText}`)\n    }\n  } catch (error) {\n    console.error(\'Error fetching\', urlPath)\n    throw error\n  }\n\n  let isHtmlFile = response.headers.get(\'Content-Type\')?.includes(\'text/html\')\n\n  // Always put `index.html` files into directories - this leads to the best\n  // support with and without trailing slashes on github pages:\n  // https://github.com/slorber/trailing-slash-guide?tab=readme-ov-file#summary\n  let outputPath = isHtmlFile\n    ? path.join(outputDir, urlPath, \'index.html\')\n    : path.join(outputDir, urlPath)\n\n  console.log(`Crawled ${urlPath} -> ./${path.relative(process.cwd(), outputPath)}`)\n\n  await fs.mkdir(path.dirname(outputPath), { recursive: true })\n\n  if (isHtmlFile) {\n    let html = await response.text()\n    await fs.writeFile(outputPath, html, \'utf-8\')\n\n    // Parse HTML files for other resources/links to add to queue\n    return {\n      downloadedUrl: urlPath,\n      discoveredUrls: parse(html)\n        .querySelectorAll(\'a:not([rel="nofollow"]),link:not([rel="preload"]):not([rel="prefetch"])\')\n        .map((link) => link.getAttribute(\'href\'))\n        .filter((href) => href && !isAbsoluteUrl(href))\n        .map((href) => resolveRelativeLink(href!, urlPath))\n        .flatMap((href) => {\n          let match = routes.docs.match(`http://localhost${href}`)\n          return match ? [href, routes.markdown.href(match.params)] : [href]\n        }),\n    }\n  } else {\n    let content = await response.arrayBuffer()\n    await fs.writeFile(outputPath, new Uint8Array(content))\n    return { downloadedUrl: urlPath, discoveredUrls: [] }\n  }\n}\n\nfunction isAbsoluteUrl(href: string): boolean {\n  return href.startsWith(\'http://\') || href.startsWith(\'https://\') || href.startsWith(\'//\')\n}\n\nfunction resolveRelativeLink(link: string, url: string): string {\n  if (link.startsWith(\'/\')) {\n    return link\n  }\n\n  // Handle relative paths like \'../\' or \'page\'\n  let base = url.endsWith(\'/\') ? url : path.dirname(url)\n  return path.posix.join(base, link)\n}\n\nasync function getVersionsToBuild(\n  outputDir: string,\n  all: boolean,\n): Promise<ServerContext[\'versions\'] | undefined> {\n  // Get all Remix v3 tags, transform them to vX.Y.Z format, sort newest to oldest\n  const remixVersions = cp\n    .execSync(\'git tag\', { encoding: \'utf-8\' })\n    .trim()\n    .split(\'\\n\')\n    .filter((tag) => tag.startsWith(\'remix@3\'))\n    .map((tag) => tag.replace(\'remix@\', \'v\'))\n    .filter((tag) => semver.valid(tag) && !semver.prerelease(tag))\n    .sort((a, b) => semver.rcompare(a, b))\n\n  if (remixVersions.length === 0) {\n    return undefined\n  } else if (all) {\n    // When --all is specified, crawl all Remix tags that don\'t currently have a\n    // set of docs on disk\n    let versions = existsSync(outputDir)\n      ? (await fs.readdir(outputDir, { withFileTypes: true }))\n          .filter((entry) => entry.isDirectory() && entry.name.startsWith(\'v\'))\n          .map((entry) => entry.name)\n      : []\n    const alreadyBuilt = new Set(versions)\n    return remixVersions.map((tag) => ({ version: tag, crawl: !alreadyBuilt.has(tag) }))\n  } else {\n    // Otherwise, just crawl the most recent tag\n    return remixVersions.map((tag) => ({\n      version: tag,\n      crawl: tag === remixVersions[0],\n    }))\n  }\n}\n',
            'docs/src/server/router.tsx': "import * as fs from 'node:fs'\nimport * as path from 'node:path'\nimport * as semver from 'semver'\nimport { type RemixNode } from 'remix/component'\nimport { renderToStream } from 'remix/component/server'\nimport { createRouter as _createRouter, type Router } from 'remix/fetch-router'\nimport { createHtmlResponse } from 'remix/response/html'\nimport { ServerPage, Home, NotFound, type ServerContext } from './components.tsx'\nimport { discoverMarkdownFiles, renderMarkdownFile } from './markdown.ts'\nimport { routes } from './routes.ts'\nimport { createFileResponse } from 'remix/response/file'\nimport { openLazyFile } from 'remix/fs'\n\nconst DOCS_DIR = path.resolve(import.meta.dirname, '..', '..')\nconst REPO_DIR = path.resolve(DOCS_DIR, '..')\nconst BUILD_DIR = path.join(REPO_DIR, 'docs', 'build')\nconst MD_DIR = path.join(BUILD_DIR, 'md')\nconst ASSETS_DIR = path.join(BUILD_DIR, 'assets')\nconst DEV_CSS_DIR = path.join(DOCS_DIR, 'public')\nconst REMIX_PKG_JSON = path.join(REPO_DIR, 'packages', 'remix', 'package.json')\n\nconst { docFiles, docFilesLookup } = await discoverMarkdownFiles(MD_DIR)\n\nexport const getDefaultVersions = (): ServerContext['versions'] => {\n  let version = JSON.parse(fs.readFileSync(REMIX_PKG_JSON, 'utf-8')).version\n  return [{ version, crawl: semver.prerelease(version) === null }]\n}\n\nexport function createRouter(versions?: ServerContext['versions']) {\n  versions ??= getDefaultVersions()\n\n  const router = _createRouter()\n\n  const respond = {\n    async file(request: Request, filePath: string, name: string) {\n      return await createFileResponse(openLazyFile(filePath, { name }), request)\n    },\n    async document(request: Request, node: RemixNode, init?: ResponseInit) {\n      let body = await stream(router, request, node, init)\n      return createHtmlResponse(body, init)\n    },\n    async fragment(request: Request, node: RemixNode, init?: ResponseInit) {\n      let body = await stream(router, request, node, init)\n      return new Response(body, {\n        ...init,\n        headers: {\n          'Content-Type': 'text/html; charset=utf-8',\n          ...init?.headers,\n        },\n      })\n    },\n  }\n\n  router.map(routes, {\n    actions: {\n      assets: ({ request, params }) => {\n        // Replicate `staticFiles` middleware but allowing for a dynamic version param\n        let devPath = path.join(DEV_CSS_DIR, params.asset)\n        let filePath =\n          process.env.NODE_ENV === 'development' && fs.existsSync(devPath)\n            ? devPath\n            : path.join(ASSETS_DIR, params.asset)\n        return respond.file(request, filePath, params.asset)\n      },\n      async docs({ request, params }) {\n        // Docs page\n        let docFile = docFiles.find((file) => file.urlPath === params.slug)\n        let node: RemixNode\n\n        if (!docFile) {\n          node = <NotFound slug={params.slug} />\n        } else {\n          let html = await renderMarkdownFile(docFile.path, docFilesLookup, params.version)\n          node = <div innerHTML={html} />\n        }\n\n        return await respond.document(\n          request,\n          <ServerPage\n            setup={{\n              docFiles,\n              versions,\n              slug: params.slug,\n              activeVersion: params.version,\n            }}\n          >\n            {node}\n          </ServerPage>,\n        )\n      },\n      async home({ request, params }) {\n        return respond.document(\n          request,\n          <ServerPage setup={{ docFiles, versions, activeVersion: params.version }}>\n            <Home />\n          </ServerPage>,\n        )\n      },\n      async markdown({ request, params }) {\n        let docFile = docFiles.find((file) => file.urlPath === params.slug)\n        if (!docFile) {\n          return new Response('Not Found', { status: 404 })\n        }\n\n        return respond.file(request, docFile.path, params.slug)\n      },\n    },\n  })\n\n  return router\n}\n\n// Response helpers\n\nfunction stream(router: Router, request: Request, node: RemixNode, init?: ResponseInit) {\n  return renderToStream(node, {\n    async resolveFrame(src) {\n      let url = new URL(src, request.url)\n\n      // IMPORTANT: this is a server-internal fetch to get *HTML*, so do not forward\n      // Accept-Encoding — otherwise compression middleware could return compressed bytes.\n      let headers = new Headers(request.headers)\n      headers.delete('accept-encoding')\n      headers.set('accept', 'text/html')\n\n      let res = await router.fetch(\n        new Request(url, {\n          method: 'GET',\n          headers,\n          signal: request.signal,\n        }),\n      )\n\n      if (!res.ok) {\n        return `<pre>Frame error: ${res.status} ${res.statusText}</pre>`\n      }\n\n      if (res.body) {\n        return res.body\n      }\n\n      return await res.text()\n    },\n  })\n}\n",
        }
